class Solution:
    def processString(self, s: str) -> str:
        digits = [c for c in s if c.isdigit()]
        letters = [c for c in s if c.isalpha()]
        # 只含字母或只含数字：原样返回
        if not digits or not letters:
            return s
        parts = []
        n = min(len(digits), len(letters))
        for i in range(n):
            d = digits[i]
            parts.append(d)
            cnt = ord(d) - ord("0")
            # 数字为 0 时不输出对应字母
            if cnt > 0:
                parts.append(letters[i] * cnt)
        # 较长一侧的余量直接拼接
        if len(digits) > len(letters):
            parts.extend(digits[n:])
        elif len(letters) > len(digits):
            parts.extend(letters[n:])
        return "".join(parts)
```

```java
public class Solution {
    public String processString(String s) {
        StringBuilder digits = new StringBuilder();
        StringBuilder letters = new StringBuilder();
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (c >= '0' && c <= '9') digits.append(c);
            else if (c >= 'A' && c <= 'Z') letters.append(c);
        }
        // 只含一类字符时直接返回原串
        if (digits.length() == 0 || letters.length() == 0) return s;
        StringBuilder res = new StringBuilder();
        int n = Math.min(digits.length(), letters.length());
        for (int i = 0; i < n; i++) {
            char d = digits.charAt(i);
            res.append(d);
            int cnt = d - '0';
            // 数字为 0 时不输出对应字母
            if (cnt > 0) {
                for (int k = 0; k < cnt; k++) res.append(letters.charAt(i));
            }
        }
        // 拼接较长一侧的余量
        if (digits.length() > n) res.append(digits.substring(n));
        else if (letters.length() > n) res.append(letters.substring(n));
        return res.toString();
    }
}
