```c
char* processString(char* s) {
    int len = strlen(s);
    // 分离数字和字母
    char* digits = (char*)malloc(len + 1);
    char* letters = (char*)malloc(len + 1);
    int d_cnt = 0, l_cnt = 0;
    for (int i = 0; i < len; i++) {
        if (s[i] >= '0' && s[i] <= '9') {
            digits[d_cnt++] = s[i];
        } else if (s[i] >= 'A' && s[i] <= 'Z') {
            letters[l_cnt++] = s[i];
        }
    }
    digits[d_cnt] = '\0';
    letters[l_cnt] = '\0';

    // 只含一类字符时直接返回原串
    if (d_cnt == 0 || l_cnt == 0) {
        free(digits);
        free(letters);
        char* result = (char*)malloc(len + 1);
        strcpy(result, s);
        return result;
    }

    // 计算输出需要的空间
    int max_out = 0;
    int n = d_cnt < l_cnt ? d_cnt : l_cnt;
    for (int i = 0; i < n; i++) {
        max_out++; // 数字本身
        int cnt = digits[i] - '0';
        if (cnt > 0) max_out += cnt; // 重复字母
    }
    // 较长一侧的余量
    if (d_cnt > l_cnt) max_out += d_cnt - n;
    else if (l_cnt > d_cnt) max_out += l_cnt - n;

    char* result = (char*)malloc(max_out + 1);
    int pos = 0;

    // 交替输出：先数字，再按数字次数重复字母
    for (int i = 0; i < n; i++) {
        result[pos++] = digits[i];
        int cnt = digits[i] - '0';
        // 数字为 0 时不输出对应字母
        if (cnt > 0) {
            for (int k = 0; k < cnt; k++) {
                result[pos++] = letters[i];
            }
        }
    }
    // 拼接较长一侧的余量
    if (d_cnt > n) {
        strcpy(result + pos, digits + n);
        pos += d_cnt - n;
    } else if (l_cnt > n) {
        strcpy(result + pos, letters + n);
        pos += l_cnt - n;
    }
    result[pos] = '\0';

    free(digits);
    free(letters);
    return result;
}
